+  const parsed = JSON.parse(output) as unknown;
+  if (!Array.isArray(parsed)) {
+    return [];
+  }
+
+  return parsed
+    .filter((item): item is { path: string; size: number } => {
+      return Boolean(
+        item &&
+          typeof item === 'object' &&
