+
+    const operation = await getWorkspaceOperation(env.DB, workspaceId, operationId);
+    if (!operation) {
+      return jsonResponse({ error: 'Operation not found' }, 404);
+    }
+
+    let payload: Record<string, unknown> = {};
+    if (operation.status === 'queued') {
+      const raw = await env.DB
+        .prepare('SELECT request_payload_json FROM workspace_operations WHERE id = ?')
+        .bind(operationId)
+        .first<{ request_payload_json: string }>();
+      if (raw?.request_payload_json) {
